export const InlineIcon: FC<IconProps & SVGAttributes<SVGElement>> = ({
  icon,
  className,
  ...props
}) => {
  const Icon = icons[icon];
  if (!Icon) {
    throw `unknown icon: ${icon}`;
  }
  return <Icon className={classNames("icon", className)} {...props} />;
}
